function o(t){if(t==null)return"¥0.00";const e=(t/100).toFixed(2);return`¥${Number(e).toLocaleString("zh-CN",{minimumFractionDigits:2})}`}function D(t){if(!t)return"-";const e=new Date(t),r=e.getFullYear(),E=String(e.getMonth()+1).padStart(2,"0"),n=String(e.getDate()).padStart(2,"0"),g=String(e.getHours()).padStart(2,"0"),a=String(e.getMinutes()).padStart(2,"0");return`${r}-${E}-${n} ${g}:${a}`}function u(t){return!t||t.length<7?t||"-":t.slice(0,3)+"****"+t.slice(-4)}function i(t){return{ACTIVE:"bg-green-100 text-green-700",INACTIVE:"bg-gray-100 text-gray-600",SOLD:"bg-blue-100 text-blue-700",PENDING:"bg-yellow-100 text-yellow-700",CERTIFIED:"bg-green-100 text-green-700",REJECTED:"bg-red-100 text-red-700",FROZEN:"bg-red-100 text-red-700",DISABLED:"bg-red-100 text-red-700",TRADING:"bg-blue-100 text-blue-700",COMPLETED:"bg-green-100 text-green-700",CANCELLED:"bg-gray-100 text-gray-600",DISPUTE:"bg-orange-100 text-orange-700",RECHARGE:"text-green-600",WITHDRAW:"text-red-600",FREEZE:"text-orange-600",UNFREEZE:"text-blue-600",REFUND:"text-red-600"}[t]||"bg-gray-100 text-gray-600"}function s(t){return{ACTIVE:"在售",INACTIVE:"已下架",SOLD:"已售出",PENDING:"待处理",PENDING_CONFIRM:"待确认",CERTIFIED:"已认证",REJECTED:"已拒绝",FROZEN:"已冻结",DISABLED:"已禁用",TRADING:"交易中",COMPLETED:"已完成",CANCELLED:"已取消",DISPUTE:"争议中",RECHARGE:"充值",WITHDRAW:"提现",FREEZE:"冻结",UNFREEZE:"解冻",REFUND:"退款",PROCESSING:"处理中",RESOLVED:"已解决"}[t]||t}export{o as a,i as b,D as f,s as g,u as m};
